import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {The algorithm selects the next node by prioritizing the nearest node with the least predicted congestion based on upcoming truck routes, also checking for potential clustering of unvisited nodes.}
    """
    # Step 1: Evaluate potential congestion based on upcoming truck destinations.
    congestion_risk = {node: 0 for node in unvisited_nodes}
    for node in truck_nodes:
        if node in unvisited_nodes:
            congestion_risk[node] += 1

    # Step 2: Identify least congested nodes and calculate distances from the current node.
    candidate_nodes = [node for node in unvisited_nodes if congestion_risk[node] == min(congestion_risk.values())]

    # Step 3: Calculate distances from current_node to each candidate node and select the nearest one.
    if candidate_nodes:
        distances = [distance_matrix[current_node, node] for node in candidate_nodes]
        next_node = candidate_nodes[np.argmin(distances)]
    else:
        distances_to_unvisited = [distance_matrix[current_node, node] for node in unvisited_nodes]
        next_node = unvisited_nodes[np.argmin(distances_to_unvisited)]

    # Step 4: Check for potential clustering of unvisited nodes and select one if within a threshold.
    cluster_threshold = np.std([distance_matrix[depot_node, node] for node in unvisited_nodes])
    clustered_nodes = [node for node in unvisited_nodes if distance_matrix[depot_node, node] < cluster_threshold]
    if clustered_nodes:
        distances_to_clustered = [distance_matrix[current_node, node] for node in clustered_nodes]
        next_node = clustered_nodes[np.argmin(distances_to_clustered)]

    return next_node
